const rows = $input.all();
const m = {}; let tenant = null;
for (const it of rows) { const j = it.json; m[j.question_key] = j.answer || ''; if (!tenant) tenant = j.tenant_id; }
const g = (k) => (m[k] || '').trim();
const NL = String.fromCharCode(10);
const parts = ['=== BUSINESS BRIEF ===','Use only facts stated here.','','--- WHAT IT IS ---', g('a1_oneliner'),'','--- PROBLEM IT SOLVES ---', g('a2_problem'),'','--- KEY NUMBERS ---', g('a3_numbers'),'','--- ICP ---', g('b1_icp'),'','--- CONTACT & CTA ---', g('a5_cta'),'','=== END BUSINESS BRIEF ==='];
let prompt = ''; for (let i=0;i<parts.length;i++){ prompt += parts[i]; if (i<parts.length-1) prompt += NL; }
return [{ json: { cag_block: prompt, tenant_id: tenant } }];
